-- From $a+d=2^k$ and $b+c=2^m$ with $k>m \geq 1$, we deduce that $a+d>b+c$.
have hd_gt_bc : a + d > b + c := by
  nlinarith only [ h₂, h₃ ];
-- From $ad=bc$ and $a+d>b+c$, we deduce that $b+c=2^m$ with $k>m \geq 1$. We also know $b+c=2^m$.
have h_m : b + c = 2 ^ m := by
  exact h₅
have h_k : a + d = 2 ^ k := by
  exact h₄
have h_km : k > m := by
  exact not_le.mp fun contra => by linarith [ Nat.pow_le_pow_right two_pos contra ] ;
have h_m_ge_1 : m ≥ 1 := by
  grind;
-- From $a+d=2^k$ and $b+c=2^m$ with $k>m \geq 1$, we deduce that $d=2^k-a$ and $c=2^m-b$.
have hd : d = 2 ^ k - a := by
  rw [ ← h_k, Nat.add_sub_cancel_left ]
have hc : c = 2 ^ m - b := by
  rw [ ← h_m, Nat.add_sub_cancel_left ];
-- From $a(2^k-a)=b(2^m-b)$, we get $2^m(b-2^{k-m}a)=b^2-a^2$, so $2^m | (b-a)(b+a)$.
have h_div : 2 ^ m ∣ (b - a) * (b + a) := by
  zify at *;
  rw [ Nat.cast_sub ( by linarith ) ];
  exact ⟨ b - 2 ^ ( k - m ) * a, by rw [ show ( 2 : ℤ ) ^ k = 2 ^ ( k - m ) * 2 ^ m by rw [ ← pow_add, Nat.sub_add_cancel ( by linarith ) ] ] at *; nlinarith ⟩;
-- Since $b-a$ and $b+a$ are both even but their difference $2a$ is not a multiple of 4, exactly one of them is a multiple of $2^{m-1}$.
have h_even_odd : (2 ^ (m - 1) ∣ b - a) ∨ (2 ^ (m - 1) ∣ b + a) := by
  -- Since $b-a$ and $b+a$ are both even but their difference $2a$ is not a multiple of 4, exactly one of them is a multiple of $2^{m-1}$ because $2^m$ divides their product.
  have h_even_odd : Nat.factorization ((b - a) * (b + a)) 2 ≥ m := by
    exact Nat.le_trans ( by simp +decide [ * ] ) ( Nat.factorization_le_iff_dvd ( by positivity ) ( by exact mul_ne_zero ( Nat.sub_ne_zero_of_lt h₂.1 ) ( by linarith ) ) |>.2 h_div 2 ) ;
  -- Since $b-a$ and $b+a$ are both even but their difference $2a$ is not a multiple of 4, exactly one of them is a multiple of $2^{m-1}$ because $2^m$ divides their product and their factorizations must add up to at least $m$.
  have h_factorization : Nat.factorization (b - a) 2 + Nat.factorization (b + a) 2 ≥ m := by
    rwa [ Nat.factorization_mul ( Nat.sub_ne_zero_of_lt h₂.1 ) ( by linarith ) ] at h_even_odd;
  have h_factorization : Nat.factorization (b - a) 2 ≤ 1 ∨ Nat.factorization (b + a) 2 ≤ 1 := by
    contrapose! h_even_odd; simp_all +decide [ Nat.factorization_eq_zero_of_not_dvd, ← even_iff_two_dvd, parity_simps ] ;
    have h_contra : 4 ∣ (b - a) ∧ 4 ∣ (b + a) := by
      exact ⟨ Nat.dvd_trans ( pow_dvd_pow _ h_even_odd.1 ) ( Nat.ordProj_dvd _ _ ), Nat.dvd_trans ( pow_dvd_pow _ h_even_odd.2 ) ( Nat.ordProj_dvd _ _ ) ⟩;
    grind;
  cases h_factorization <;> [ right; left ] <;> exact Nat.dvd_trans ( pow_dvd_pow _ <| Nat.sub_le_of_le_add <| by linarith ) <| Nat.ordProj_dvd _ _;
rcases m with ( _ | m ) <;> simp_all +decide [ pow_succ' ];
rcases h_even_odd with ( h | h );
· linarith [ Nat.le_of_dvd ( Nat.sub_pos_of_lt h₂.1 ) h, Nat.sub_add_cancel h₂.1.le ];
· obtain ⟨ x, hx ⟩ := h; rcases x with ( _ | _ | x ) <;> simp_all! +arith +decide;
  · norm_num [ show b = 2 ^ m - a by rw [ ← hx, Nat.add_sub_cancel_left ] ] at *;
    -- From $a * (2^k - a) = (2^m - a) * (2 * 2^m - (2^m - a))$, we get $a * 2^k = 2^{2m}$.
    have h_eq : a * 2 ^ k = 2 ^ (2 * m) := by
      rw [ Nat.pow_mul' ];
      nlinarith only [ Nat.sub_add_cancel ( show a ≤ 2 ^ m from le_of_lt ( Nat.lt_of_sub_pos h₀.2.1 ) ), Nat.sub_add_cancel ( show 2 ^ m - a ≤ 2 * 2 ^ m from by linarith ), h₃, h₄ ];
    -- From $a * 2^k = 2^{2m}$, we get $a = 2^{2m - k}$.
    have h_a : a = 2 ^ (2 * m - k) := by
      exact mul_left_cancel₀ ( pow_ne_zero k two_ne_zero ) ( by rw [ ← pow_add, Nat.add_sub_of_le ( show k ≤ 2 * m from le_of_not_gt fun h => by nlinarith only [ h_eq, h, pow_pos ( zero_lt_two' ℕ ) k, pow_lt_pow_right₀ ( show 1 < 2 by decide ) h, h₀ ] ) ] ; linarith );
    grind;
  · grind

